#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<int>a(n),ans(n,-1);for(auto&x:a)scanf("%d",&x);stack<int>st;for(int i=0;i<n;i++){while(!st.empty()&&a[st.top()]<a[i]){ans[st.top()]=a[i];st.pop();}st.push(i);}string out;for(int i=0;i<n;i++){out+=to_string(ans[i]);out+=' ';}out.pop_back();printf("%s\n",out.c_str());}
